#!/bin/bash
# Runs the Go pre-build quality gates: gofmt format check (with
# auto-skip for generated files), `go vet`, `go test`, and
# `govulncheck` reachable-vuln scan.
#
# Lives in a separate composite from the release-side build steps
# (build/actions/go/release/) so the calling reusable workflow can
# run quality checks with `contents: read` while the release job
# (which invokes goreleaser, the only step that genuinely needs
# `contents: write`) runs with the stronger permission. The cost is
# one extra checkout + setup-go per build; the benefit is that the
# `go test` step — which executes arbitrary adopter test code —
# cannot push to the repo even if compromised.
#
# Pure decision functions (`is_generated_file`, `list_unformatted`,
# `count_findings`) live alongside main() so test.bats can source
# this file and call them directly, mirroring
# build/actions/npm/build_and_pack.sh's three-layer pattern (pure
# function tests, behavioral tests against fixture dirs, integration
# tests via PATH-shimmed toolchains).
#
# Failure semantics:
#   - gofmt/vet/test failures fail the build (these are quality gates).
#   - govulncheck findings are INFORMATIONAL: counted, summarized to
#     $GITHUB_STEP_SUMMARY and the JSON written to <metadata_dir>/
#     govulncheck.json, but do NOT fail the build. Matches OSV-Scanner's
#     posture in actions/scan. Reasoning in build/actions/go/SPEC.md
#     "Failure semantics."
#   - govulncheck tool errors (network, infra) still propagate.
#
# Usage: build/actions/go/checks/run_checks.sh <path> <metadata_dir>
#                                              <govulncheck_version>
#                                              <run_race> <run_gofmt>
#
#   path:                 project directory (already validated by
#                         the composite's validate_inputs.sh)
#   metadata_dir:         workspace-relative dir for govulncheck.json
#                         (e.g., metadata/go/_/). MUST exist; caller
#                         creates it.
#   govulncheck_version:  pinned semver (e.g., v1.1.4). Wrangle never
#                         takes `latest`/`main` — see CLAUDE.md
#                         "Supply Chain Discipline."
#   run_race:             "true" → `go test -race`; anything else →
#                         plain `go test`. CGO-disabled builds must
#                         pass "false" because the race detector
#                         requires cgo.
#   run_gofmt:            "true" → run gofmt check (with the
#                         generated-file auto-skip below);
#                         anything else → skip gofmt entirely.

set -euo pipefail
set -f  # processes external arguments — disable globbing per CLAUDE.md

# Pure function: returns 0 iff the file carries the standard Go
# generated-code header within its first five lines. Go's convention
# says "near the top of the file" — golangci-lint scans the first
# ~5 lines so a leading copyright header doesn't push the marker out
# of range. Common shape:
#   // Copyright <year> <author>
#   // (blank)
#   // Code generated by <tool>. DO NOT EDIT.
# The regex matches Go's documented marker exactly:
# https://pkg.go.dev/cmd/go/internal/generate
#
# Args: <file_path>
is_generated_file() {
    local file="$1"
    [[ -f "$file" ]] || return 1
    head -5 "$file" 2>/dev/null | grep -qE '^// Code generated .* DO NOT EDIT\.$'
}

# Pure function: list files in <project_dir> that are not gofmt-clean,
# EXCLUDING generated files. Prints one filename per line to stdout.
# Empty stdout (no output) means everything is formatted.
#
# Args: <project_dir>
list_unformatted() {
    local path="$1"
    (
        cd "$path"
        # gofmt -l writes filenames to stdout. Stderr (e.g., syntax
        # errors) goes to the step log, not into the filename stream
        # — otherwise an unparseable file would surface here as a
        # confusing "this file is not gofmt-clean" listing its
        # syntax-error line. go vet (run after) catches the syntax
        # error with a clear message.
        gofmt -l . | while read -r f; do
            [[ -n "$f" ]] || continue
            if is_generated_file "$f"; then
                continue
            fi
            printf '%s\n' "$f"
        done
    )
}

# Pure function: count the number of finding records in a
# govulncheck -json output file. Each finding emits a JSON object
# with a top-level `finding` key. We parse the JSON stream with jq
# rather than grep — a literal grep on `"finding"` would drift on
# any future govulncheck schema addition like `findings_url`,
# `finding_count`, or a vuln ID containing the substring.
#
# govulncheck -json emits a stream of JSON objects (one per
# protocol message, NDJSON-style). `jq -s` reads the whole stream
# as an array; the filter selects elements where `.finding` is
# non-null and prints the length.
#
# govulncheck -json ALWAYS exits 0 on a successful scan regardless
# of findings; tool errors (network, infra) are the only non-zero
# exit signal. So a missing file just means no scan happened —
# return 0 rather than failing.
#
# Args: <json_path>
# Prints: integer >= 0
count_findings() {
    local json="$1"
    if [[ ! -s "$json" ]]; then
        printf '0\n'
        return
    fi
    jq -s '[.[] | select(.finding != null)] | length' "$json"
}

# Pure function: install govulncheck via `go install` at the pinned
# version. Idempotent — `go install` is a no-op if the version is
# already on the module cache + GOBIN. Resolves GOBIN explicitly so
# the caller can locate the binary without re-querying.
#
# Args: <version>
# Prints: absolute path to the installed govulncheck binary
install_govulncheck() {
    local version="$1"
    local gobin
    gobin="$(go env GOBIN)"
    if [[ -z "$gobin" ]]; then
        gobin="$(go env GOPATH)/bin"
    fi
    # Integrity via sum.golang.org tlog (pinned semver); no upstream binary
    # release. See CLAUDE.md "Supply Chain Discipline" (Go modules installed
    # via `go install`).
    #
    # Assert the module-proxy / sumdb path is in effect so the security
    # claim is not environment-conditional. The Go toolchain exposes
    # several env knobs that can silently weaken or disable the sumdb
    # check:
    #   - GOPROXY=direct or GOPROXY=off bypasses the proxy (`,direct`
    #     fallback after https://proxy.golang.org is fine — sumdb is
    #     consulted in both proxy and direct fetches).
    #   - GOSUMDB=off disables the tlog check entirely.
    #   - GOPRIVATE=*, GONOSUMDB=*, GOINSECURE=* (any non-empty value)
    #     skip the sumdb for matching module paths; a wildcard pattern
    #     skips it for every module path including govulncheck's.
    #   - GOFLAGS=-insecure (or any GOFLAGS containing -insecure) lets
    #     the toolchain fetch over plain HTTP and bypass sumdb.
    # Per CLAUDE.md "NEVER fall back to a weaker verification method,"
    # if any of these is set in the parent env we fail loudly rather
    # than silently install with degraded integrity. Detection runs in
    # the parent shell (before the subshell prefix below) so the unset
    # values from the subshell don't mask a hostile parent setting.
    # Detect+abort rather than `env -u`-unsetting: operator misconfig
    # surfaces loudly instead of being silently papered over.
    # _bypass_var is loop-controlled — the values are the hardcoded
    # literals on the `for` line, never external input. The indirect
    # expansion `${!_bypass_var:-}` is safe here for that reason; do
    # NOT extend this loop to iterate over a caller-supplied list
    # without re-validating, or the indirection becomes injection-prone.
    local _bypass_var
    for _bypass_var in GOPRIVATE GONOSUMDB GOINSECURE; do
        if [[ -n "${!_bypass_var:-}" ]]; then
            printf 'install_govulncheck: refusing to install with %s=%q set in the environment — this would skip the sum.golang.org integrity check. Unset it (or run on a clean CI env) and retry.\n' \
                "$_bypass_var" "${!_bypass_var}" >&2
            exit 1
        fi
    done
    if [[ "${GOFLAGS:-}" == *-insecure* ]]; then
        printf 'install_govulncheck: refusing to install with GOFLAGS=%q (contains -insecure) — this would skip the sum.golang.org integrity check. Unset it and retry.\n' \
            "$GOFLAGS" >&2
        exit 1
    fi
    # Belt-and-braces: pin the proxy + sumdb for the subshell that
    # runs `go install`. This defeats GOPROXY=direct/off and GOSUMDB=off
    # in the parent env without overriding the caller's broader env.
    # Combined with the bypass-var checks above, the security claim
    # holds regardless of parent env shape.
    GOPROXY="https://proxy.golang.org,direct" GOSUMDB="sum.golang.org" \
        go install "golang.org/x/vuln/cmd/govulncheck@${version}" 1>&2
    printf '%s/govulncheck\n' "$gobin"
}

# --- step functions --------------------------------------------------
#
# main() orchestrates these. Each step takes only the arguments it
# needs and is independently testable.

# Run the gofmt format check. Exits 1 if unformatted files are
# found, 0 otherwise (including when skipped via run_gofmt="false").
# Args: <input_path> <run_gofmt>
run_gofmt_step() {
    local input_path="$1"
    local run_gofmt="$2"
    if [[ "$run_gofmt" != "true" ]]; then
        printf '== gofmt check ==\nSkipped (run-gofmt-check: false).\n'
        return 0
    fi
    printf '== gofmt check ==\n'
    local unformatted
    unformatted="$(list_unformatted "$input_path")"
    if [[ -n "$unformatted" ]]; then
        printf 'Error: the following files are not gofmt-clean:\n'
        printf '%s\n' "$unformatted"
        # shellcheck disable=SC2016 # backticks here are human-readable formatting, not command substitution
        printf 'Run `gofmt -w .` locally to fix, then commit.\n'
        # shellcheck disable=SC2016
        printf 'If the file is generated and missing the `// Code generated ... DO NOT EDIT.` header,\n'
        printf 'add that header (Go convention) — wrangle will auto-skip it. Or disable the gofmt\n'
        printf 'check entirely via run-gofmt-check: false on the action input.\n'
        return 1
    fi
    printf 'gofmt: all files are formatted (generated files auto-skipped).\n'
}

# Run `go vet ./...`. Args: <input_path>
run_vet_step() {
    local input_path="$1"
    printf '\n== go vet ==\n'
    ( cd "$input_path" && go vet ./... )
    printf 'go vet: passed.\n'
}

# Run the test suite, optionally with the race detector.
# Args: <input_path> <run_race>
run_test_step() {
    local input_path="$1"
    local run_race="$2"
    printf '\n== go test ./... ==\n'
    if [[ "$run_race" == "true" ]]; then
        ( cd "$input_path" && go test -race ./... )
        printf 'go test: passed (with race detector).\n'
    else
        ( cd "$input_path" && go test ./... )
        printf 'go test: passed (race detector skipped via run-race-detector: false).\n'
    fi
}

# Install govulncheck, run it, write JSON to <metadata_dir>/govulncheck.json,
# and print the finding count. Findings are informational (never
# fail the build); tool errors propagate.
# Args: <input_path> <metadata_dir_abs> <govulncheck_version>
# Prints: integer finding count to stdout (caller can capture)
run_govulncheck_step() {
    local input_path="$1"
    local metadata_dir_abs="$2"
    local version="$3"
    printf '\n== govulncheck ==\n' >&2
    local govuln_bin govuln_out
    govuln_bin="$(install_govulncheck "$version")"
    govuln_out="$metadata_dir_abs/govulncheck.json"

    # govulncheck -json exits 0 even on findings (findings live in
    # the JSON, not the exit code); non-zero means a tool error
    # (network, infra). Tool errors propagate; findings don't fail.
    set +e
    ( cd "$input_path" && "$govuln_bin" -json ./... ) > "$govuln_out"
    local status=$?
    set -e

    if (( status != 0 )); then
        printf 'govulncheck: tool error (exit %d). JSON output: %s\n' "$status" "$govuln_out" >&2
        exit "$status"
    fi

    local findings
    findings="$(count_findings "$govuln_out")"
    if (( findings == 0 )); then
        printf 'govulncheck: no reachable vulnerabilities.\n' >&2
    else
        printf 'govulncheck: %s reachable vulnerability finding(s) (informational; not failing the build).\n' "$findings" >&2
        printf 'JSON output: %s\n' "$govuln_out" >&2
        # shellcheck disable=SC2016 # backticks here are human-readable formatting, not command substitution
        printf 'Re-run locally with `govulncheck ./...` for human-readable findings.\n' >&2
    fi
    printf '%s\n' "$findings"
}

# Append the quality-checks step summary block to $GITHUB_STEP_SUMMARY.
# Args: <run_gofmt> <run_race> <findings>
write_step_summary() {
    local run_gofmt="$1"
    local run_race="$2"
    local findings="$3"
    [[ -n "${GITHUB_STEP_SUMMARY:-}" ]] || return 0
    {
        printf '## Go quality checks\n\n'
        printf '| Check | Result |\n|---|---|\n'
        if [[ "$run_gofmt" == "true" ]]; then
            printf '| gofmt | passed (generated files auto-skipped) |\n'
        else
            printf '| gofmt | skipped |\n'
        fi
        printf '| go vet | passed |\n'
        if [[ "$run_race" == "true" ]]; then
            printf '| go test | passed (with race detector) |\n'
        else
            printf '| go test | passed |\n'
        fi
        printf '| govulncheck | %s reachable finding(s) — informational |\n' "$findings"
    } >> "$GITHUB_STEP_SUMMARY"
}

# --- main orchestrator -----------------------------------------------

main() {
    if [[ $# -ne 5 ]]; then
        printf 'Usage: %s <path> <metadata_dir> <govulncheck_version> <run_race> <run_gofmt>\n' "$0" >&2
        exit 1
    fi

    local input_path="$1"
    local metadata_dir="$2"
    local govulncheck_version="$3"
    local run_race="$4"
    local run_gofmt="$5"

    # Resolve the metadata path BEFORE any cd, so subsequent writes
    # resolve to the workspace root. realpath -m handles trailing
    # slashes correctly — a dirname/basename recompose would produce
    # "metadata/go" given input "metadata/go/" because basename strips
    # trailing slashes.
    mkdir -p "$metadata_dir"
    local metadata_dir_abs
    metadata_dir_abs="$(realpath -m "$metadata_dir")"

    run_gofmt_step "$input_path" "$run_gofmt"
    run_vet_step "$input_path"
    run_test_step "$input_path" "$run_race"

    local findings
    findings="$(run_govulncheck_step "$input_path" "$metadata_dir_abs" "$govulncheck_version")"

    write_step_summary "$run_gofmt" "$run_race" "$findings"
}

# Sourcing guard: tests source this file to call decision functions
# directly without running the full pipeline.
if [[ "${BASH_SOURCE[0]}" == "${0}" ]]; then
    main "$@"
fi
